'use client';

import Link from 'next/link';
import { usePathname, useRouter } from 'next/navigation';
import { 
  LayoutDashboard, 
  Users, 
  CalendarCheck, 
  CreditCard, 
  Calendar, 
  FileText, 
  Settings, 
  LogOut,
  Menu
} from 'lucide-react';
import { useStore } from '@/store/useStore';
import { apiClient } from '@/lib/api-client';

export default function Sidebar() {
  const pathname = usePathname();
  const router = useRouter();
  const { sidebarCollapsed, setSidebarCollapsed, logout } = useStore();

  const handleLogout = async () => {
    try {
      await apiClient.post('/api/auth/logout');
      logout();
      router.push('/auth');
    } catch (err) {
      console.error('Logout failed:', err);
      logout();
      router.push('/auth');
    }
  };

  const menuItems = [
    { name: 'Dashboard', path: '/dashboard', icon: LayoutDashboard },
    { name: 'Employees', path: '/dashboard/employees', icon: Users },
    { name: 'Attendance', path: '/dashboard/attendance', icon: CalendarCheck },
    { name: 'Payroll', path: '/dashboard/payroll', icon: CreditCard },
    { name: 'Leave Management', path: '/dashboard/leaves', icon: Calendar },
    { name: 'Reports', path: '/dashboard/reports', icon: FileText },
    { name: 'Settings', path: '/dashboard/settings', icon: Settings },
  ];

  return (
    <aside 
      className={`fixed top-0 left-0 z-40 h-screen border-r bg-[var(--sidebar-bg)] border-[var(--sidebar-border)] text-[var(--text-primary)] transition-all duration-300 no-print
        ${sidebarCollapsed ? 'w-[80px]' : 'w-[280px]'}
      `}
    >
      {/* Sidebar Header */}
      <div className={`flex h-16 items-center border-b border-[var(--sidebar-border)] px-4
        ${sidebarCollapsed ? 'justify-center' : 'justify-between'}
      `}>
        {sidebarCollapsed ? (
          <button
            onClick={() => setSidebarCollapsed(false)}
            className="flex h-10 w-10 items-center justify-center rounded-xl hover:bg-slate-50 dark:hover:bg-slate-800 text-[var(--text-secondary)] hover:text-blue-600 transition-colors"
          >
            <Menu size={20} />
          </button>
        ) : (
          <>
            <div className="flex items-center gap-2.5 overflow-hidden pl-2">
              {/* Logo Icon matching reference */}
              <svg width="24" height="24" viewBox="0 0 24 24" fill="none" xmlns="http://www.w3.org/2000/svg" className="text-blue-600 shrink-0">
                <rect x="2" y="2" width="8" height="8" rx="2" fill="#2563eb" />
                <rect x="14" y="2" width="8" height="8" rx="2" fill="#2563eb" opacity="0.7" />
                <rect x="2" y="14" width="8" height="8" rx="2" fill="#2563eb" opacity="0.7" />
                <circle cx="18" cy="18" r="4" fill="#2563eb" />
              </svg>
              <span className="font-extrabold text-xl tracking-tight text-slate-800 dark:text-white">
                PPS
              </span>
            </div>
            <button
              onClick={() => setSidebarCollapsed(true)}
              className="flex h-8 w-8 items-center justify-center rounded-lg hover:bg-slate-50 dark:hover:bg-slate-800 text-[var(--text-secondary)] hover:text-blue-600 dark:hover:text-blue-400 transition-colors"
            >
              <Menu size={20} />
            </button>
          </>
        )}
      </div>

      {/* Sidebar Navigation */}
      <nav className="flex flex-col h-[calc(100vh-4rem)] justify-between p-4">
        <div className="space-y-1">
          {menuItems.map((item) => {
            const Icon = item.icon;
            const isActive = pathname === item.path || (item.path !== '/dashboard' && pathname.startsWith(item.path));
            
            return (
              <Link
                key={item.name}
                href={item.path}
                className={`flex items-center gap-3 rounded-xl px-4 py-3 text-sm font-medium transition-all duration-200 group relative
                  ${isActive 
                    ? 'bg-blue-50/70 dark:bg-blue-950/20 text-blue-600 dark:text-blue-400 font-semibold' 
                    : 'text-[var(--text-secondary)] hover:bg-slate-50 dark:hover:bg-slate-800/40 hover:text-[var(--text-primary)]'
                  }
                `}
                title={sidebarCollapsed ? item.name : undefined}
              >
                <Icon 
                  size={18} 
                  className={`shrink-0 transition-transform duration-200 group-hover:scale-105
                    ${isActive ? 'text-blue-600 dark:text-blue-400' : 'text-[var(--text-muted)] group-hover:text-[var(--text-primary)]'}
                  `} 
                />
                {!sidebarCollapsed && <span className="truncate">{item.name}</span>}
              </Link>
            );
          })}
        </div>

        {/* Logout Button */}
        <div>
          <button
            onClick={handleLogout}
            className="flex w-full items-center gap-3 rounded-xl px-4 py-3 text-sm font-semibold text-red-500 hover:bg-red-50 dark:hover:bg-red-950/10 transition-all duration-200 group"
            title={sidebarCollapsed ? 'Logout' : undefined}
          >
            <LogOut size={18} className="shrink-0 text-red-500 group-hover:translate-x-0.5 transition-transform" />
            {!sidebarCollapsed && <span>Logout</span>}
          </button>
        </div>
      </nav>
    </aside>
  );
}
