'use client';

import { useState, useEffect } from 'react';
import { useRouter } from 'next/navigation';
import { 
  Search, 
  Bell, 
  Sun, 
  Moon, 
  ChevronDown, 
  Menu,
  X,
  LogOut,
  User,
  Settings as SettingsIcon,
  CalendarDays
} from 'lucide-react';
import { useStore } from '@/store/useStore';
import { apiClient } from '@/lib/api-client';

export default function Navbar() {
  const router = useRouter();
  const { 
    user, 
    theme, 
    toggleTheme, 
    sidebarCollapsed, 
    setSidebarCollapsed,
    logout,
    notifications,
    setNotifications,
    markNotificationsAsRead
  } = useStore();

  const [searchQuery, setSearchQuery] = useState('');
  const [showNotifications, setShowNotifications] = useState(false);
  const [showProfileDropdown, setShowProfileDropdown] = useState(false);

  // Fetch notifications on mount
  useEffect(() => {
    if (user) {
      apiClient.get('/api/notifications')
        .then(res => {
          if (res.success) {
            setNotifications(res.data);
          }
        })
        .catch(err => console.error('Error fetching notifications:', err));
    }
  }, [user, setNotifications]);

  const handleLogout = async () => {
    try {
      await apiClient.post('/api/auth/logout');
      logout();
      router.push('/auth');
    } catch (err) {
      logout();
      router.push('/auth');
    }
  };

  const handleMarkAllRead = async () => {
    try {
      await apiClient.put('/api/notifications');
      markNotificationsAsRead();
    } catch (err) {
      console.error('Error marking notifications as read:', err);
    }
  };

  const unreadCount = notifications.filter(n => !n.isRead).length;

  return (
    <header className="sticky top-0 z-30 flex h-16 w-full items-center justify-between px-6 glass-navbar no-print">
      {/* Search and Mobile Menu Icon */}
      <div className="flex items-center gap-4 flex-1 max-w-md">
        {/* Toggle mobile sidebar */}
        <button
          onClick={() => setSidebarCollapsed(!sidebarCollapsed)}
          className="flex h-10 w-10 items-center justify-center rounded-xl border border-[var(--navbar-border)] hover:bg-slate-50 dark:hover:bg-slate-800 text-[var(--text-secondary)] transition-colors md:hidden"
        >
          <Menu size={20} />
        </button>

        {/* Global Search Bar */}
        <div className="relative w-full hidden sm:block">
          <Search 
            size={16} 
            className="absolute top-1/2 left-3.5 -translate-y-1/2 text-[var(--text-muted)]" 
          />
          <input
            type="text"
            placeholder="Search..."
            value={searchQuery}
            onChange={(e) => setSearchQuery(e.target.value)}
            className="w-full h-10 rounded-xl border border-[var(--navbar-border)] bg-[var(--card-bg)] pl-10 pr-4 text-sm text-[var(--text-primary)] placeholder-[var(--text-muted)] focus:border-blue-500/50 focus:outline-none transition-all"
          />
        </div>
      </div>

      {/* Top Bar Actions */}
      <div className="flex items-center gap-4">
        {/* Dark/Light Mode Toggle */}
        <button
          onClick={toggleTheme}
          className="flex h-10 w-10 items-center justify-center rounded-xl border border-[var(--navbar-border)] bg-[var(--card-bg)] hover:bg-slate-50 dark:hover:bg-slate-800 text-[var(--text-secondary)] hover:text-blue-600 dark:hover:text-blue-400 transition-colors"
          title="Toggle Theme"
        >
          {theme === 'light' ? <Moon size={18} /> : <Sun size={18} />}
        </button>

        {/* Notification Bell */}
        <div className="relative">
          <button
            onClick={() => {
              setShowNotifications(!showNotifications);
              setShowProfileDropdown(false);
            }}
            className="flex h-10 w-10 items-center justify-center rounded-xl border border-[var(--navbar-border)] bg-[var(--card-bg)] hover:bg-slate-50 dark:hover:bg-slate-800 text-[var(--text-secondary)] hover:text-blue-600 dark:hover:text-blue-400 transition-colors"
          >
            <Bell size={18} />
            {unreadCount > 0 && (
              <span className="absolute -top-1 -right-1 flex h-4 w-4 items-center justify-center rounded-full bg-blue-600 text-[9px] font-black text-white shadow-sm ring-2 ring-white dark:ring-gray-900 animate-pulse">
                {unreadCount}
              </span>
            )}
          </button>

          {/* Notifications Dropdown */}
          {showNotifications && (
            <div className="absolute right-0 mt-2.5 w-80 rounded-2xl border border-[var(--card-border)] bg-[var(--card-bg)]/95 backdrop-blur-xl shadow-xl overflow-hidden py-1 animate-in fade-in slide-in-from-top-2 duration-200 z-50">
              <div className="flex items-center justify-between px-4 py-2.5 border-b border-[var(--card-border)]">
                <span className="font-bold text-xs text-[var(--text-primary)]">Notifications</span>
                {unreadCount > 0 && (
                  <button 
                    onClick={handleMarkAllRead}
                    className="text-[10px] font-bold text-blue-600 hover:text-blue-500 dark:text-blue-400 dark:hover:text-blue-300 transition-colors"
                  >
                    Mark all read
                  </button>
                )}
              </div>
              <div className="max-h-60 overflow-y-auto">
                {notifications.length === 0 ? (
                  <div className="px-4 py-6 text-center text-xs text-[var(--text-muted)]">
                    No new notifications
                  </div>
                ) : (
                  notifications.map((notif) => (
                    <div 
                      key={notif.id} 
                      className={`px-4 py-2.5 border-b border-[var(--card-border)] last:border-0 hover:bg-slate-50 dark:hover:bg-slate-800/60 transition-colors
                        ${!notif.isRead ? 'bg-blue-50/20 dark:bg-blue-950/10' : ''}
                      `}
                    >
                      <div className="flex items-start justify-between gap-1">
                        <span className="font-bold text-xs text-[var(--text-primary)]">{notif.title}</span>
                        <span className="text-[9px] text-[var(--text-muted)] font-medium shrink-0">
                          {new Date(notif.createdAt).toLocaleTimeString([], { hour: '2-digit', minute: '2-digit' })}
                        </span>
                      </div>
                      <p className="text-xs text-[var(--text-secondary)] mt-0.5 leading-relaxed">{notif.message}</p>
                    </div>
                  ))
                )}
              </div>
            </div>
          )}
        </div>

        {/* User Profile Dropdown */}
        <div className="relative">
          <button
            onClick={() => {
              setShowProfileDropdown(!showProfileDropdown);
              setShowNotifications(false);
            }}
            className="flex items-center gap-3 rounded-xl border border-[var(--navbar-border)] bg-[var(--card-bg)] px-3 py-1.5 text-left hover:bg-slate-50 dark:hover:bg-slate-800 transition-all"
          >
            {/* User Avatar - circular headshot or fallback */}
            {user?.avatar ? (
              <img
                src={user.avatar}
                alt={user.name}
                className="h-8 w-8 rounded-full object-cover border border-slate-200"
              />
            ) : (
              <div className="flex h-8 w-8 items-center justify-center rounded-full bg-blue-50 dark:bg-blue-950 text-blue-600 dark:text-blue-400 font-black text-xs uppercase shadow-sm">
                {user?.name ? user.name.split(' ').map(n => n[0]).join('') : 'U'}
              </div>
            )}
            
            <div className="hidden sm:block">
              <div className="text-xs font-bold text-[var(--text-primary)] leading-tight">{user?.name || 'Administrator'}</div>
              <div className="text-[10px] text-[var(--text-muted)] font-medium leading-tight">{user?.roleLabel || 'Admin'}</div>
            </div>
            
            <ChevronDown size={14} className="text-[var(--text-muted)]" />
          </button>

          {/* Profile Dropdown list */}
          {showProfileDropdown && (
            <div className="absolute right-0 mt-2.5 w-56 rounded-2xl border border-[var(--card-border)] bg-[var(--card-bg)]/95 backdrop-blur-xl shadow-xl overflow-hidden py-1 animate-in fade-in slide-in-from-top-2 duration-200 z-50">
              <div className="px-4 py-2.5 border-b border-[var(--card-border)]">
                <div className="text-xs font-bold text-[var(--text-primary)]">{user?.name}</div>
                <div className="text-[10px] text-[var(--text-muted)] truncate mt-0.5">{user?.email}</div>
              </div>
              <div className="py-1">
                <button 
                  onClick={() => {
                    setShowProfileDropdown(false);
                    router.push('/dashboard/profile');
                  }}
                  className="flex w-full items-center gap-2 px-4 py-2.5 text-xs font-medium text-[var(--text-secondary)] hover:bg-slate-50 dark:hover:bg-slate-800 hover:text-blue-600 dark:hover:text-blue-400 transition-colors"
                >
                  <User size={14} />
                  My Profile
                </button>
                <button 
                  onClick={() => {
                    setShowProfileDropdown(false);
                    router.push('/dashboard/settings');
                  }}
                  className="flex w-full items-center gap-2 px-4 py-2.5 text-xs font-medium text-[var(--text-secondary)] hover:bg-slate-50 dark:hover:bg-slate-800 hover:text-blue-600 dark:hover:text-blue-400 transition-colors"
                >
                  <SettingsIcon size={14} />
                  Settings
                </button>
              </div>
              <div className="border-t border-[var(--card-border)] py-1">
                <button
                  onClick={handleLogout}
                  className="flex w-full items-center gap-2 px-4 py-2.5 text-xs font-bold text-red-500 hover:bg-red-50 dark:hover:bg-red-950/10 transition-colors"
                >
                  <LogOut size={14} />
                  Sign Out
                </button>
              </div>
            </div>
          )}
        </div>
      </div>
    </header>
  );
}
