'use client';

import { useEffect, useState } from 'react';
import { useRouter } from 'next/navigation';
import Sidebar from '@/components/layout/Sidebar';
import Navbar from '@/components/layout/Navbar';
import { useStore } from '@/store/useStore';
import { apiClient } from '@/lib/api-client';

export default function DashboardLayout({
  children,
}: {
  children: React.ReactNode;
}) {
  const router = useRouter();
  const { user, setUser, sidebarCollapsed } = useStore();
  const [loading, setLoading] = useState(true);

  useEffect(() => {
    // Verify session
    apiClient.get('/api/auth/me')
      .then(res => {
        if (res.success) {
          setUser(res.user);
        } else {
          router.push('/auth');
        }
      })
      .catch(() => {
        router.push('/auth');
      })
      .finally(() => {
        setLoading(false);
      });
  }, [setUser, router]);

  if (loading) {
    return (
      <div className="flex h-screen w-screen items-center justify-center bg-[var(--background)]">
        <div className="flex flex-col items-center gap-4">
          {/* Custom Spinner */}
          <div className="h-10 w-10 animate-spin rounded-full border-4 border-blue-200 border-t-blue-600"></div>
          <span className="text-sm font-semibold text-[var(--text-secondary)] animate-pulse">Loading payroll portal...</span>
        </div>
      </div>
    );
  }

  // Double check auth
  if (!user) return null;

  return (
    <div className="min-h-screen bg-[var(--background)]">
      {/* Sidebar - fixed left */}
      <Sidebar />

      {/* Main Content Wrap */}
      <div 
        className={`flex flex-col min-h-screen transition-all duration-300
          ${sidebarCollapsed ? 'md:pl-[80px]' : 'md:pl-[280px]'}
        `}
      >
        {/* Sticky Top Navbar */}
        <Navbar />

        {/* Dynamic page contents */}
        <main className="flex-1 p-6 md:p-8 animate-in fade-in duration-300">
          {children}
        </main>
      </div>
    </div>
  );
}
